    public static String getStepTypeColor(String steptype) {
        if (steptype.equalsIgnoreCase("ActionBlock") || steptype.equalsIgnoreCase("Groovy")) {
            return "#E6E4E4";
        }
        if (steptype.equalsIgnoreCase("CategoryMaint")) {
            return "#D6ADFF";
        }
        if (steptype.equalsIgnoreCase("COC") || steptype.equalsIgnoreCase("eSig")) {
            return "#E7F2F8";
        }
        if (steptype.equalsIgnoreCase("DataEntry") || steptype.equalsIgnoreCase("DataEntryPage")) {
            return "#FDFFB6";
        }
        if (steptype.equalsIgnoreCase("eForm") || steptype.equalsIgnoreCase("eFormSelector") || steptype.equalsIgnoreCase("Form")) {
            return "#F8E5C7";
        }
        if (steptype.equalsIgnoreCase("HTML")) {
            return "#F7B5F7";
        }
        if (steptype.equalsIgnoreCase("JSP") || steptype.equalsIgnoreCase("WebPage") || steptype.equalsIgnoreCase("ListPage") || steptype.equalsIgnoreCase("MaintPage")) {
            return "#BBFD9B";
        }
        if (steptype.equalsIgnoreCase("Noop") || steptype.equalsIgnoreCase("Splitter") || steptype.equalsIgnoreCase("Wait") || steptype.equalsIgnoreCase("Converter")) {
            return "#FDFDFD";
        }
        if (steptype.equalsIgnoreCase("PrimaryMaintForm")) {
            return "#C4FFEF";
        }
        if (steptype.equalsIgnoreCase("QCSequence")) {
            return "#F7A1D0";
        }
        if (steptype.equalsIgnoreCase("QueueSelector") || steptype.equalsIgnoreCase("ScanSelector")) {
            return "#A1ABF7";
        }
        if (steptype.equalsIgnoreCase("Report")) {
            return "#BEFF59";
        }
        if (steptype.equalsIgnoreCase("VariableInput")) {
            return "#74DCFD";
        }
        return "";
    }

    public static String[] getStepTypes() {
        return new String[]{"ActionBlock", "CategoryMaint", "COC", "Converter", "DataEntry", "DataEntryPage", "eForm", "eFormSelector", "eSig", "Form", "Groovy", "HTML", "JSP", "ListPage", "MaintPage", "Noop", "PrimaryMaintForm", "QCSequence", "QueueSelector", "Report", "ScanSelector", "Splitter", "VariableInput", "Wait", "WebPage"};
    }

    public static String[] getAutoExecuteStepTypes() {
        return new String[]{"ActionBlock", "Converter", "Groovy", "Noop", "Splitter"};
    }
